"use client";

import * as React from "react";
import { Slider as BaseSlider } from "@base-ui/react/slider";
import { cn } from "@/lib/utils";

/**
 * Liquid-glass Slider — Base UI's Slider (drag, keyboard, ARIA) with a glass-bead
 * thumb over a translucent track and a gradient fill. Behavior is Base UI's; the
 * glass is the skin. Forwards all Slider.Root props (value/defaultValue/min/max/step…).
 */
function GlassSlider({ className, ...props }: React.ComponentProps<typeof BaseSlider.Root>) {
  return (
    <BaseSlider.Root className={cn("w-full", className)} {...props}>
      <BaseSlider.Control className="flex w-full touch-none items-center py-3 select-none">
        <BaseSlider.Track className="relative h-2 w-full rounded-full bg-white/15 ring-1 ring-white/10">
          <BaseSlider.Indicator className="rounded-full bg-gradient-to-r from-[#12d3ff] to-[#ff5db1]" />
          <BaseSlider.Thumb
            className={cn(
              "size-5 rounded-full bg-gradient-to-b from-white to-white/85 outline-none transition-transform",
              "shadow-[inset_0_1px_1px_rgb(255_255_255/70%),0_2px_6px_-1px_rgb(0_0_0/40%)]",
              "focus-visible:ring-2 focus-visible:ring-white/60 data-[dragging]:scale-110",
            )}
          />
        </BaseSlider.Track>
      </BaseSlider.Control>
    </BaseSlider.Root>
  );
}

export { GlassSlider };
